parameters.jsCode:
const pqrs = $input.all().map(i => i.json);
const ayer = new Date(Date.now()-86400000).toLocaleDateString('es-CO', {year:'numeric',month:'long',day:'numeric'});

const total = pqrs.length;
const byTipo = {};
const byEstado = {};
const byPrioridad = {};

for (const p of pqrs) {
  byTipo[p.tipo_pqr]       = (byTipo[p.tipo_pqr]       || 0) + 1;
  byEstado[p.estado]       = (byEstado[p.estado]       || 0) + 1;
  byPrioridad[p.prioridad] = (byPrioridad[p.prioridad] || 0) + 1;
}

const filasTipo = Object.entries(byTipo).map(([k,v]) => `<tr><td style='padding:8px;border:1px solid #e5e7eb;text-transform:capitalize;'>${k}</td><td style='padding:8px;border:1px solid #e5e7eb;text-align:center;font-weight:bold;'>${v}</td><td style='padding:8px;border:1px solid #e5e7eb;text-align:center;'>${((v/total)*100).toFixed(1)}%</td></tr>`).join('');
const filasEstado = Object.entries(byEstado).map(([k,v]) => `<tr><td style='padding:8px;border:1px solid #e5e7eb;text-transform:capitalize;'>${k}</td><td style='padding:8px;border:1px solid #e5e7eb;text-align:center;font-weight:bold;'>${v}</td></tr>`).join('');

const html = `
<div style='font-family:Arial,sans-serif;max-width:700px;'>
  <div style='background:#1e3a5f;padding:20px;border-radius:8px 8px 0 0;'>
    <h1 style='color:#fff;margin:0;font-size:20px;'>📊 Reporte Diario PQR — ${ayer}</h1>
    <p style='color:#93c5fd;margin:4px 0 0;font-size:13px;'>Tododrogas CIA SAS</p>
  </div>
  <div style='border:1px solid #ddd;padding:24px;background:#fff;'>
    <div style='display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-bottom:24px;'>
      <div style='background:#eff6ff;border-radius:8px;padding:16px;text-align:center;'>
        <div style='font-size:36px;font-weight:bold;color:#1d4ed8;'>${total}</div>
        <div style='font-size:13px;color:#6b7280;'>PQR Recibidas</div>
      </div>
      <div style='background:#f0fdf4;border-radius:8px;padding:16px;text-align:center;'>
        <div style='font-size:36px;font-weight:bold;color:#16a34a;'>${byEstado.resuelto||byEstado.solucionado||0}</div>
        <div style='font-size:13px;color:#6b7280;'>Resueltas</div>
      </div>
      <div style='background:#fef2f2;border-radius:8px;padding:16px;text-align:center;'>
        <div style='font-size:36px;font-weight:bold;color:#dc2626;'>${byPrioridad.alta||0}</div>
        <div style='font-size:13px;color:#6b7280;'>Alta Prioridad</div>
      </div>
    </div>
    <h3 style='color:#374151;'>Por Tipo:</h3>
    <table style='width:100%;border-collapse:collapse;'>
      <tr style='background:#f9fafb;'><th style='padding:8px;border:1px solid #e5e7eb;text-align:left;'>Tipo</th><th style='padding:8px;border:1px solid #e5e7eb;'>Cantidad</th><th style='padding:8px;border:1px solid #e5e7eb;'>%</th></tr>
      ${filasTipo}
    </table>
    <h3 style='color:#374151;margin-top:20px;'>Por Estado:</h3>
    <table style='width:100%;border-collapse:collapse;'>
      <tr style='background:#f9fafb;'><th style='padding:8px;border:1px solid #e5e7eb;text-align:left;'>Estado</th><th style='padding:8px;border:1px solid #e5e7eb;'>Cantidad</th></tr>
      ${filasEstado}
    </table>
    <p style='margin-top:20px;'><a href='https://td-pruebas.online/admin_v9.html' style='background:#1e3a5f;color:#fff;padding:10px 20px;text-decoration:none;border-radius:6px;display:inline-block;'>Ver Panel Completo →</a></p>
  </div>
</div>`;

return [{ json: { html, fecha: ayer, total } }];

